function downloadGeneratedPDF() {
  if (data.success && data.pdf) {
    const timestamp = Date.now();
    const outputDir = path.join(process.cwd(), "output");
    const outputPath = path.join(outputDir, `${timestamp}.pdf`);

    if (!fs.existsSync(outputDir)) {
      fs.mkdirSync(outputDir, { recursive: true });
    }

    console.log("Converting Base64 string to binary buffer...");
    const buffer = Buffer.from(data.pdf, "base64");

    console.log(`Writing file to: ${outputPath}`);
    fs.writeFileSync(outputPath, buffer);

    console.log("✅ PDF downloaded successfully to your current path!");
  } else {
    console.error("Failed to extract PDF data string from response layout.");
  }
}

downloadGeneratedPDF();
